mapper.select:
SELECT ap.id, ap.name, ap.route, ap.method, COUNT(aps.id_endpoint) AS total_call FROM api_endpoint ap INNER JOIN api_usage aps ON aps.id_endpoint = ap.id WHERE aps.id_user = #{employee_id} AND ap.is_delete = 0 AND ap.is_active = 1
AND `route` LIKE CONCAT("%",#{keyword}, "%")
GROUP BY ap.id ORDER BY total_call DESC;
